/**
 * SceneManager
 *
 * Owns Three.js scene/camera/renderer + render loop and basic raycasting helpers.
 */

import * as THREE from 'three';

export class SceneManager {
  /**
   * @param {object} opts
   * @param {HTMLElement} opts.container
   */
  constructor({ container }) {
    this.container = container;
    this.scene = new THREE.Scene();

    // Slightly wider default FOV for a "zoomed out" initial view.
    this.camera = new THREE.PerspectiveCamera(90, 1, 0.1, 2000);
    this.camera.position.set(0, 0, 0);

    this.renderer = new THREE.WebGLRenderer({ antialias: true, alpha: false });
    this.renderer.setClearColor(0x0b0f19, 1);
    this.renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
    this.renderer.setSize(1, 1, false);
    this.renderer.outputColorSpace = THREE.SRGBColorSpace;
    this.renderer.xr.enabled = true;

    this.canvas = this.renderer.domElement;
    this.canvas.classList.add('p360-canvas');
    this.container.appendChild(this.canvas);

    this.raycaster = new THREE.Raycaster();
    this.pointerNdc = new THREE.Vector2();

    this._onResize = this._onResize.bind(this);
    this._anim = this._anim.bind(this);

    this._running = false;
    this._beforeRender = [];
    this._afterRender = [];

    window.addEventListener('resize', this._onResize, { passive: true });
    this._onResize();
  }

  onBeforeRender(fn) {
    this._beforeRender.push(fn);
  }

  onAfterRender(fn) {
    this._afterRender.push(fn);
  }

  setPointerFromClient(clientX, clientY) {
    const rect = this.canvas.getBoundingClientRect();
    const x = (clientX - rect.left) / rect.width;
    const y = (clientY - rect.top) / rect.height;
    this.pointerNdc.set(x * 2 - 1, -(y * 2 - 1));
  }

  intersectObjects(objects, recursive = true) {
    this.raycaster.setFromCamera(this.pointerNdc, this.camera);
    return this.raycaster.intersectObjects(objects, recursive);
  }

  start() {
    if (this._running) return;
    this._running = true;
    this.renderer.setAnimationLoop(this._anim);
  }

  stop() {
    if (!this._running) return;
    this._running = false;
    this.renderer.setAnimationLoop(null);
  }

  _anim(timeMs) {
    for (const fn of this._beforeRender) fn(timeMs);
    this.renderer.render(this.scene, this.camera);
    for (const fn of this._afterRender) fn(timeMs);
  }

  _onResize() {
    const rect = this.container.getBoundingClientRect();
    const w = Math.max(1, Math.floor(rect.width));
    const h = Math.max(1, Math.floor(rect.height));
    this.camera.aspect = w / h;
    this.camera.updateProjectionMatrix();
    this.renderer.setSize(w, h, false);
  }

  destroy() {
    this.stop();
    window.removeEventListener('resize', this._onResize);
    if (this.canvas?.parentNode) this.canvas.parentNode.removeChild(this.canvas);
    this.renderer.dispose();
  }
}


