/**
 * VRManager
 *
 * Optional WebXR support:
 * - VRButton UI
 * - Select interaction via controller `select` events (works for gaze/tap devices too)
 */

import * as THREE from 'three';
import { VRButton } from 'three/examples/jsm/webxr/VRButton.js';

export class VRManager {
  /**
   * @param {object} opts
   * @param {import('three').WebGLRenderer} opts.renderer
   * @param {import('three').Scene} opts.scene
   * @param {import('three').PerspectiveCamera} opts.camera
   * @param {(intersection: import('three').Intersection | null) => void} opts.onSelectIntersection
   */
  constructor({ renderer, scene, camera, onSelectIntersection, onSessionStart, onSessionEnd }) {
    this.renderer = renderer;
    this.scene = scene;
    this.camera = camera;
    this.onSelectIntersection = onSelectIntersection;
    this.onSessionStart = onSessionStart;
    this.onSessionEnd = onSessionEnd;

    this.enabled = false;
    this._hotspotObjects = [];

    this._controller = null;
    this._raycaster = new THREE.Raycaster();
    this._tmpMatrix = new THREE.Matrix4();

    this._buttonEl = null;
    this._isPresenting = false;
  }

  setHotspotObjects(objects) {
    this._hotspotObjects = objects || [];
  }

  enable({ domRoot } = {}) {
    if (this.enabled) return;
    this.enabled = true;

    this._buttonEl = VRButton.createButton(this.renderer);
    this._buttonEl.classList.add('p360-btn');
    if (domRoot) domRoot.appendChild(this._buttonEl);
    else document.body.appendChild(this._buttonEl);

    this._controller = this.renderer.xr.getController(0);
    this._controller.addEventListener('select', () => this._handleSelect());
    this.scene.add(this._controller);

    this.renderer.xr.addEventListener('sessionstart', () => {
      this._isPresenting = true;
      this.onSessionStart?.();
    });
    this.renderer.xr.addEventListener('sessionend', () => {
      this._isPresenting = false;
      this.onSessionEnd?.();
    });
  }

  isPresenting() {
    return this._isPresenting;
  }

  _handleSelect() {
    const hit = this._intersectFromController();
    this.onSelectIntersection?.(hit);
  }

  _intersectFromController() {
    if (!this._controller) return null;
    this._tmpMatrix.identity().extractRotation(this._controller.matrixWorld);

    this._raycaster.ray.origin.setFromMatrixPosition(this._controller.matrixWorld);
    this._raycaster.ray.direction.set(0, 0, -1).applyMatrix4(this._tmpMatrix);
    const hits = this._raycaster.intersectObjects(this._hotspotObjects, true);
    return hits[0] || null;
  }

  /**
   * Best-effort programmatic exit.
   */
  async exit() {
    const session = this.renderer.xr.getSession?.();
    if (session) await session.end();
  }

  /**
   * Programmatic enter via VRButton click.
   * Must be called from a user gesture to succeed in most browsers.
   */
  async requestEnter() {
    if (this._buttonEl) this._buttonEl.click();
  }

  getButtonEl() {
    return this._buttonEl;
  }

  destroy() {
    if (this._controller) this.scene.remove(this._controller);
    if (this._buttonEl?.parentNode) this._buttonEl.parentNode.removeChild(this._buttonEl);
    this._buttonEl = null;
  }
}


