/**
 * Panorama
 *
 * Equirectangular panorama rendered on an inside-facing sphere.
 */

import * as THREE from 'three';
import { createTextureLoader } from './Utils.js';

export class Panorama {
  /**
   * @param {object} opts
   * @param {number} [opts.radius]
   */
  constructor({ radius = 500 } = {}) {
    THREE.Cache.enabled = true;
    this.radius = radius;
    this.mesh = null;
    this._loader = createTextureLoader();
  }

  async load(imageUrl) {
    if (!imageUrl) throw new Error('Panorama360: panorama.image_url is missing');
    const texture = await this._loadTexture(imageUrl);
    texture.colorSpace = THREE.SRGBColorSpace;
    texture.minFilter = THREE.LinearMipmapLinearFilter;
    texture.magFilter = THREE.LinearFilter;
    texture.anisotropy = 8;

    const geometry = new THREE.SphereGeometry(this.radius, 60, 40);
    geometry.scale(-1, 1, 1); // inside-facing sphere

    const material = new THREE.MeshBasicMaterial({ map: texture });
    const mesh = new THREE.Mesh(geometry, material);
    mesh.name = 'PanoramaSphere';
    mesh.frustumCulled = false;

    this.dispose();
    this.mesh = mesh;
    return mesh;
  }

  _loadTexture(url) {
    return new Promise((resolve, reject) => {
      this._loader.load(
        url,
        (tex) => resolve(tex),
        undefined,
        (err) => reject(new Error(`Panorama360: failed to load texture: ${url} (${err?.message || 'error'})`))
      );
    });
  }

  dispose() {
    if (!this.mesh) return;
    const mesh = this.mesh;
    this.mesh = null;
    if (mesh.geometry) mesh.geometry.dispose();
    if (mesh.material?.map) mesh.material.map.dispose();
    if (mesh.material) mesh.material.dispose();
  }
}


